331	  function to_gray(value : u_unsigned) return std_ulogic_vector is
332	    variable value_slv, result : std_ulogic_vector(value'range) := (others => '0');
333	  begin
334	    value_slv := std_ulogic_vector(value);
335	    result := value_slv xor "0" & value_slv(value_slv'high downto 1);
336	    return result;
337	  end function;
